example.code:
"use client";

import { z } from "zod";
import { useRef } from "react";
import {
  IGRPForm,
  IGRPInputText,
  IGRPButton,
  type IGRPFormHandle,
} from "@igrp/igrp-framework-react-design-system";

const schema = z.object({
  name: z.string().min(1),
  email: z.string().email(),
});

export function UserForm() {
  const formRef = useRef<IGRPFormHandle<typeof schema> | null>(null);
  return (
    <IGRPForm
      schema={schema}
      formRef={formRef}
      onSubmit={async (v) => {
        // call a server action here
      }}
    >
      <IGRPInputText name="name" label="Name" required />
      <IGRPInputText name="email" label="Email" type="email" required />
      <IGRPButton type="submit">Submit</IGRPButton>
    </IGRPForm>
  );
}
